try:
    import json

    new_messages = []


    with servicebus_client:
        receiver = servicebus_client.get_subscription_receiver(topic_name=topic_name, subscription_name=subscription_name)
        with receiver:
            received_msgs = receiver.peek_messages( max_message_count=20) 
            for msg in received_msgs:
                msg = json.loads(str(msg))
                if isinstance(msg, list):
                    new_messages.extend(msg)
                elif isinstance(msg, dict):
                    new_messages.append(msg)

    if len(new_messages) == 0:
        mssparkutils.notebook.exit(False)

    new_messages = json.dumps(new_messages)
except:
    mssparkutils.notebook.exit(False)
